VALUES
  ('social-worker-moex-06030', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關於男性在配偶懷孕期間，也會出現害喜現象的說明，何者錯誤？', '["因為嫉妒孕婦，所產生的生理變化", "因為即將為人父，所產生的身體焦慮", "因為照顧孕婦，身體疲累所產生的正常生理反應", "因為這些害喜現象，能幫助男性進入父親角色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06031', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關嬰幼兒與主要照顧者間的依附關係之敘述，下列何者錯誤？', '["居住在安置機構之嬰幼兒，一定會與主要照顧者發生依附關係不佳狀況", "依附關係不佳會讓嬰幼兒出現情緒冷漠、生理、智力等面向退化的情形", "時常更換領養或寄養家庭的嬰幼兒，因為缺乏穩定及持久的關愛，容易出現依附關係不佳的問題", "依附關係不佳或從來沒有建立依附關係，所產生的問題，比失去主要照顧者更為嚴重"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06032', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '目前自殺問題在國內日趨嚴重，對自殺之敘述下列何者正確？', '["自殺危機過後就能馬上再以正常人的態度視之", "只有中年失業男人或有憂鬱症的年長者會自殺", "自殺的人通常會在自殺前發出自殺意念的訊息", "走上自殺之路的人是抱著必死決心"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06033', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「靈性層面」（spiritual dimension）是社會工作者在評估（assessment）個案的重要面向之一，請問下列 敘述，何者錯誤？', '["所謂的靈性，指的是人們對於自我實存、信仰以及超自然力量經驗的整體", "靈性面向是獨特的，社會工作者不應與個案的心理社會環境與功能程度一起進行評估", "各種宗教會以更正式的儀式和有系統的方式去建構靈性", "若社會工作者與個案有不同的靈性傾向、信念與經驗時，代表著個案的語言與行為，可能與社會工作 者的思想及經驗架構不同的意涵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06034', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '中文每每一字多義，必須掌握文脈才能解釋得宜，下列那一選項「卒」字用法與其 他三者不同？', '["民莫不穀，我獨不「卒」（《詩經．蓼莪》）", "其囚及期，而「卒」自歸（歐陽修〈縱囚論〉）", "而田忌一不勝而再勝，「卒」得王千金（《史記．孫子吳起列傳》）", "石崇以奢靡誇人，「卒」以此死東市（司馬光〈訓儉示康〉）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06035', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '語文使用上有所謂「偏義複詞」，該用語的意義偏重在某一個語素上，另一個語素 的意義消失，只起陪襯作用。下列各「」中的詞語，何者不是偏義複詞？', '["萬一你有個「好歹」，父母會多麼傷心呢", "我忘記多年來的「甘苦」，心底充滿了感謝", "「買賣」雙方應以誠信為原則，生意才做得長久", "你去看看外面有什麼「動靜」，再決定如何行動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06036', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列常用題辭，正確的選項是？', '["祝賀小吳結婚可用「椿萱並茂」", "祝賀蔡爺爺八十歲壽誕可用「道範長存」", "祝賀王先生印刷工廠開業可用「里仁為美」", "祝賀張媽媽高雄新屋落成可用「堂構更新」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06037', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '信封上的啓封詞，下列選項，何者錯誤？', '["對身分較尊的用「鈞啓」", "對師長用「道啓」", "對晚輩用「台啓」", "對家庭尊長用「安啓」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06038', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩詞中，不是用來表達「羈旅思鄉情懷」的選項是：', '["君自故鄉來，應知故鄉事。來日綺窗前，寒梅著花未", "客行雖云樂，不如早旋歸。出戶獨徬徨，愁思當告誰", "山中相送罷，日暮掩柴扉。春草明年綠，王孫歸不歸", "移舟泊煙渚，日暮客愁新。野曠天低樹，江清月近人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06039', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '元代關漢卿的小令〈四塊玉．閑適〉：「南畝耕，東山臥。世態人情經歷多。閑將 往事思量過，賢的是他，愚的是我，爭甚麼。」下列賞析何者錯誤？', '["題目稱「閑適」，但實際是以「反語見意」的寫法，表示對當時現實的憤慨", "「世態人情經歷多」，寫歸隱山林的原因，「多」字流露對世態炎涼、人情冷暖 的感受", "「南畝耕，東山臥」寫歸隱後的田園生活，和陶淵明〈歸園田居〉「開荒南野際， 守拙歸園田」之意境相同", "「賢的是他，愚的是我，爭甚麼」傳達出老子「水善利萬物而不爭，…夫唯不爭， 故無尤」的豁達胸襟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
